updated as (
  update public.food_catalog fc
  set
    canonical_name = s.canonical_name,
    calorie_range = s.calorie_range,
    macros = s.macros,
    food_items = s.food_items,
    judgement_tags = s.judgement_tags,
    dish_summary = s.dish_summary,
    suggestion = s.suggestion,
    is_beverage = s.is_beverage,
    is_food = s.is_food,
    is_active = s.is_active,
    source = s.source,
    verified_level = s.verified_level,
    reference_used = s.reference_used,
    beverage_profile = s.beverage_profile
  from seed s
  where lower(btrim(fc.food_name)) = lower(btrim(s.food_name))
    and coalesce(fc.lang, 'zh-TW') = s.lang
    and coalesce(fc.is_active, true) = true
  returning fc.id
)
insert into public.food_catalog (
  lang, food_name, canonical_name, calorie_range, macros, food_items,
  judgement_tags, dish_summary, suggestion, is_beverage, is_food, is_active,
  source, verified_level, reference_used, beverage_profile
)
select
  s.lang, s.food_name, s.canonical_name, s.calorie_range, s.macros, s.food_items,
  s.judgement_tags, s.dish_summary, s.suggestion, s.is_beverage, s.is_food, s.is_active,
  s.source, s.verified_level, s.reference_used, s.beverage_profile
from seed s
where not exists (
  select 1
  from public.food_catalog fc
  where lower(btrim(fc.food_name)) = lower(btrim(s.food_name))
    and coalesce(fc.lang, 'zh-TW') = s.lang
    and coalesce(fc.is_active, true) = true
);

commit;
